{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "followup_strategist_output",
  "type": "object",
  "required": [
    "lead_id",
    "priority_tier",
    "available_channels",
    "missing_contact_fields",
    "next_best_action",
    "fallback_action",
    "followup_sequence_7d",
    "capture_next",
    "availability_queried",
    "why_this_plan",
    "risk_flags"
  ],
  "additionalProperties": false,
  "properties": {
    "lead_id": {
      "type": "string",
      "description": "Echoed exactly from lead_intelligence_output.lead_id. Never generated or modified."
    },
    "priority_tier": {
      "type": "string",
      "enum": ["hot", "warm", "cold", "unknown"],
      "description": "Echoed from input. Never re-derived."
    },
    "available_channels": {
      "type": "array",
      "items": { "type": "string", "enum": ["call", "sms", "email", "whatsapp"] },
      "description": "Channels available based on contact fields present."
    },
    "missing_contact_fields": {
      "type": "array",
      "items": { "type": "string", "enum": ["phone", "email", "name"] },
      "description": "Contact fields not captured. Empty array if all present."
    },
    "next_best_action": {
      "type": "object",
      "required": ["channel", "timing", "objective", "message", "cta"],
      "additionalProperties": false,
      "properties": {
        "channel": {
          "type": "string",
          "enum": ["call", "sms", "email", "whatsapp", "no_action"]
        },
        "timing": {
          "type": "string",
          "enum": ["immediate", "today", "24h", "3_days", "next_week"]
        },
        "objective": {
          "type": "string",
          "enum": ["post_booking_confirmation", "close", "overcome_objection", "nurture", "low_touch_nurture", "clarify_intent"]
        },
        "message": {
          "type": "object",
          "required": ["sms", "whatsapp", "email", "call"],
          "additionalProperties": false,
          "properties": {
            "sms": {
              "type": ["string", "null"],
              "maxLength": 160,
              "description": "Plain text only. Null if channel is not sms."
            },
            "whatsapp": {
              "type": ["string", "null"],
              "maxLength": 300,
              "description": "Conversational tone. Null if channel is not whatsapp."
            },
            "email": {
              "type": ["object", "null"],
              "additionalProperties": false,
              "properties": {
                "subject": {
                  "type": ["string", "null"],
                  "maxLength": 50
                },
                "body": {
                  "type": ["string", "null"],
                  "description": "3–5 sentences."
                }
              },
              "description": "Null if channel is not email."
            },
            "call": {
              "type": ["object", "null"],
              "additionalProperties": false,
              "properties": {
                "opening_line": { "type": ["string", "null"] },
                "talking_points": {
                  "type": ["array", "null"],
                  "items": { "type": "string" },
                  "minItems": 2,
                  "maxItems": 3
                },
                "closing_cta": { "type": ["string", "null"] }
              },
              "description": "Null if channel is not call."
            }
          }
        },
        "cta": {
          "type": "string",
          "description": "One-line summary of the desired customer action."
        }
      }
    },
    "fallback_action": {
      "type": "object",
      "required": ["channel", "timing_if_no_response", "message"],
      "additionalProperties": false,
      "properties": {
        "channel": {
          "type": "string",
          "enum": ["call", "sms", "email", "whatsapp", "no_action"]
        },
        "timing_if_no_response": {
          "type": ["string", "null"],
          "enum": ["24h", "3_days", "next_week", null]
        },
        "message": {
          "type": ["string", "null"],
          "maxLength": 160,
          "description": "Single line plain text regardless of channel. Null for no_action."
        }
      }
    },
    "followup_sequence_7d": {
      "type": "array",
      "minItems": 1,
      "maxItems": 5,
      "items": {
        "type": "object",
        "required": ["day", "channel", "goal"],
        "additionalProperties": false,
        "properties": {
          "day": {
            "type": "integer",
            "minimum": 0,
            "maximum": 7
          },
          "channel": {
            "type": "string",
            "enum": ["call", "sms", "email", "whatsapp", "no_action"]
          },
          "goal": { "type": "string" }
        }
      }
    },
    "capture_next": {
      "type": ["object", "null"],
      "additionalProperties": false,
      "properties": {
        "fields_to_collect": {
          "type": "array",
          "items": { "type": "string", "enum": ["phone", "email", "name"] }
        },
        "suggested_ask": {
          "type": "string",
          "description": "One natural sentence the rep can say verbatim."
        }
      },
      "required": ["fields_to_collect", "suggested_ask"],
      "description": "Null when missing_contact_fields is empty."
    },
    "availability_queried": {
      "type": "boolean",
      "description": "True if query_franchise_availability tool was called."
    },
    "why_this_plan": {
      "type": "array",
      "items": { "type": "string" },
      "minItems": 1,
      "description": "Narrative explaining the chosen strategy. All reasoning goes here."
    },
    "risk_flags": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Populated whenever a guardrail condition is met."
    }
  }
}

