parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "outreach_executor_output",
  "type": "object",
  "required": [
    "lead_id",
    "priority_tier",
    "channel_executed",
    "attempt_type",
    "execution_status",
    "external_ref_id",
    "delivery_status",
    "executed_at",
    "answered_by",
    "message_snapshot",
    "fallback_triggered",
    "fallback_reason",
    "risk_flags",
    "execution_notes"
  ],
  "additionalProperties": false,
  "properties": {
    "lead_id": {
      "type": "string",
      "description": "Echoed exactly from followup_strategist_output.lead_id. Never generated or modified."
    },
    "priority_tier": {
      "type": "string",
      "enum": ["hot", "warm", "cold", "unknown"],
      "description": "Echoed from followup_strategist_output. Never re-derived."
    },
    "channel_executed": {
      "type": "string",
      "enum": ["call", "sms", "email", "whatsapp", "no_action"],
      "description": "The channel that was actually executed (primary or fallback). no_action when channel was no_action or all execution attempts failed."
    },
    "attempt_type": {
      "type": "string",
      "enum": ["primary", "fallback", "none"],
      "description": "primary when next_best_action was executed successfully. fallback when primary failed and fallback_action was used. none when channel is no_action."
    },
    "execution_status": {
      "type": "string",
      "enum": ["sent", "queued", "failed", "no_action", "contact_missing", "message_missing"],
      "description": "sent: SMS or email dispatched. queued: outbound call placed and queued by Twilio (final outcome arrives via status callback). failed: all send attempts failed. no_action: channel was no_action. contact_missing: required contact field absent. message_missing: message content was null."
    },
    "external_ref_id": {
      "type": ["string", "null"],
      "description": "Twilio Call SID for calls (CAxxxxxxxx), Twilio Message SID for SMS (SMxxxxxxxx), SendGrid message ID for email. Null when execution failed or no_action."
    },
    "delivery_status": {
      "type": "string",
      "enum": ["sent", "delivered", "queued", "ringing", "in-progress", "completed", "no-answer", "busy", "failed", "unknown", "pending", "no_action"],
      "description": "Status returned by the send integration. For call: Twilio initial status (queued/ringing); final statuses (completed/no-answer/busy/failed) arrive via status callback and are written by the orchestrator. no_action when channel was no_action."
    },
    "answered_by": {
      "type": ["string", "null"],
      "enum": ["human", "machine", "fax", "unknown", null],
      "description": "Twilio machine detection result for call channel only. Always null on initial output — populated asynchronously by orchestrator when status callback fires. Null for SMS and email channels."
    },
    "executed_at": {
      "type": ["string", "null"],
      "description": "ISO 8601 UTC timestamp of when the send tool was called. Null when no send tool was called."
    },
    "message_snapshot": {
      "type": "object",
      "required": ["sms", "email", "call"],
      "additionalProperties": false,
      "description": "Snapshot of the exact message content that was sent. Only the sub-field for the executed channel is populated; all others are null.",
      "properties": {
        "sms": {
          "type": ["string", "null"],
          "maxLength": 160,
          "description": "Exact SMS text sent. Null if channel was not sms or whatsapp."
        },
        "email": {
          "type": ["object", "null"],
          "additionalProperties": false,
          "properties": {
            "subject": {
              "type": ["string", "null"],
              "maxLength": 50
            },
            "body": {
              "type": ["string", "null"]
            }
          },
          "description": "Null if channel was not email."
        },
        "call": {
          "type": ["object", "null"],
          "additionalProperties": false,
          "properties": {
            "opening_line": { "type": ["string", "null"] },
            "talking_points": {
              "type": ["array", "null"],
              "items": { "type": "string" },
              "minItems": 2,
              "maxItems": 3
            },
            "closing_cta": { "type": ["string", "null"] }
          },
          "description": "Null if channel was not call."
        }
      }
    },
    "fallback_triggered": {
      "type": "boolean",
      "description": "True when primary execution failed and the fallback send tool was called (regardless of fallback outcome)."
    },
    "fallback_reason": {
      "type": ["string", "null"],
      "description": "Human-readable description of why primary execution failed. Null when fallback_triggered is false."
    },
    "risk_flags": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Populated whenever a guardrail condition is met during execution."
    },
    "execution_notes": {
      "type": "array",
      "items": { "type": "string" },
      "minItems": 1,
      "description": "Narrative explaining what was executed, what tools were called, and any issues encountered. All execution reasoning goes here."
    }
  }
}
